mapper.select:
SELECT r.id, r.registration_no AS registrationNo, r.patient_id AS patientId, r.patient_name AS patientName, r.phone, r.gender, r.age, r.department_name AS departmentName, r.doctor_id AS doctorId, r.doctor_name AS doctorName, r.visit_type AS visitType, r.visit_time AS visitTime, r.status, r.registration_fee AS registrationFee, r.diagnosis_fee AS diagnosisFee, r.remark, COALESCE(m.level_name, p.member_level) AS memberLevel FROM clinic_registration r LEFT JOIN clinic_patient p ON p.id = r.patient_id AND p.deleted = 0 LEFT JOIN clinic_member m ON m.patient_id = r.patient_id AND m.deleted = 0 WHERE r.deleted = 0
AND r.status IN ('PENDING', 'WAITING') AND r.status IN ('PROCESSING', 'IN_PROGRESS') AND r.status IN ('DONE', 'COMPLETED', 'FINISHED') AND r.status = #{status}
AND (r.patient_name LIKE CONCAT('%',#{keyword},'%') OR r.phone LIKE CONCAT('%',#{keyword},'%') OR r.registration_no LIKE CONCAT('%',#{keyword},'%')) AND r.department_name = #{department} AND r.doctor_name = #{doctor} AND DATE(r.visit_time) >= #{startDate} AND DATE(r.visit_time) <= #{endDate} ORDER BY r.visit_time DESC

choose.when:
SELECT t.id, CASE UPPER(COALESCE(t.transaction_type, '')) WHEN 'RECHARGE' THEN '充值' WHEN 'REFUND' THEN '充值退款' WHEN 'CONSUME' THEN '消费' WHEN 'CONSUMPTION' THEN '消费' WHEN 'CONSUME_REFUND' THEN '消费退款' WHEN 'CONSUMPTION_REFUND' THEN '消费退款' WHEN 'ADJUST_BALANCE' THEN '余额调整' WHEN 'BALANCE_ADJUST' THEN '余额调整' WHEN 'ADJUST_POINTS' THEN '积分调整' WHEN 'POINTS_ADJUST' THEN '积分调整' ELSE COALESCE(t.transaction_type, '') END AS tradeType, m.card_no AS cardNo, m.patient_name AS memberName, t.amount, 0 AS gift, t.amount AS total, t.balance_after AS balance, '会员卡' AS payment, t.created_at AS tradeTime, t.operator FROM clinic_member_transaction t LEFT JOIN clinic_member m ON m.id = t.member_id AND m.deleted = 0 WHERE t.deleted = 0 AND DATE(t.created_at) >= #{startDate} AND DATE(t.created_at) <= #{endDate}
AND (UPPER(t.transaction_type) = 'RECHARGE' OR t.transaction_type = '充值') AND (UPPER(t.transaction_type) = 'REFUND' OR t.transaction_type = '充值退款') AND (UPPER(t.transaction_type) IN ('CONSUME', 'CONSUMPTION') OR t.transaction_type = '消费') AND (UPPER(t.transaction_type) IN ('CONSUME_REFUND', 'CONSUMPTION_REFUND') OR t.transaction_type = '消费退款') AND t.transaction_type = #{tradeType}
AND (m.card_no LIKE CONCAT('%', #{keyword}, '%') OR m.patient_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY t.id DESC

SELECT COALESCE(cashier, '未分配') AS cashier, COALESCE(department_name, '未分配') AS department, COUNT(*) AS chargeCount, SUM(CASE WHEN refund_amount > 0 THEN 1 ELSE 0 END) AS refundCount, COALESCE(SUM(receivable_amount), 0) AS receivable, COALESCE(SUM(discount_amount), 0) AS discount, COALESCE(SUM(paid_amount - COALESCE(refund_amount, 0)), 0) AS received, COALESCE(SUM(CASE WHEN pay_method = '医保' THEN paid_amount ELSE 0 END) - SUM(CASE WHEN refund_method = '医保' THEN refund_amount ELSE 0 END), 0) AS medical, COALESCE(SUM(CASE WHEN pay_method = '会员卡' THEN paid_amount ELSE 0 END) - SUM(CASE WHEN refund_method = '会员卡' THEN refund_amount ELSE 0 END), 0) AS memberCard, COALESCE(SUM(CASE WHEN pay_method = '现金' THEN paid_amount ELSE 0 END) - SUM(CASE WHEN refund_method = '现金' THEN refund_amount ELSE 0 END), 0) AS cash, COALESCE(SUM(CASE WHEN pay_method = '支付宝' THEN paid_amount ELSE 0 END) - SUM(CASE WHEN refund_method = '支付宝' THEN refund_amount ELSE 0 END), 0) AS alipay, COALESCE(SUM(CASE WHEN pay_method = '微信' THEN paid_amount ELSE 0 END) - SUM(CASE WHEN refund_method = '微信' THEN refund_amount ELSE 0 END), 0) AS wechat, COALESCE(SUM(CASE WHEN pay_method = '银行卡' THEN paid_amount ELSE 0 END) - SUM(CASE WHEN refund_method = '银行卡' THEN refund_amount ELSE 0 END), 0) AS bank FROM clinic_charge_order WHERE deleted = 0 AND DATE(COALESCE(paid_at, created_at)) >= #{startDate} AND DATE(COALESCE(paid_at, created_at)) <= #{endDate} AND department_name = #{department} AND cashier = #{cashier}
AND (order_no LIKE CONCAT('%', #{keyword}, '%') OR patient_name LIKE CONCAT('%', #{keyword}, '%') OR cashier LIKE CONCAT('%', #{keyword}, '%') OR department_name LIKE CONCAT('%', #{keyword}, '%'))
GROUP BY cashier, department_name ORDER BY received DESC

SELECT COALESCE(department_name, '未分配') AS department, COUNT(*) AS visits, COALESCE(SUM(paid_amount - COALESCE(refund_amount, 0)), 0) AS received, COALESCE(SUM(CASE WHEN pay_method = '医保' THEN paid_amount ELSE 0 END) - SUM(CASE WHEN refund_method = '医保' THEN refund_amount ELSE 0 END), 0) AS medical, COALESCE(SUM(CASE WHEN pay_method = '会员卡' THEN paid_amount ELSE 0 END) - SUM(CASE WHEN refund_method = '会员卡' THEN refund_amount ELSE 0 END), 0) AS memberCard, COALESCE(SUM(CASE WHEN pay_method = '现金' THEN paid_amount ELSE 0 END) - SUM(CASE WHEN refund_method = '现金' THEN refund_amount ELSE 0 END), 0) AS cash, COALESCE(SUM(CASE WHEN pay_method = '支付宝' THEN paid_amount ELSE 0 END) - SUM(CASE WHEN refund_method = '支付宝' THEN refund_amount ELSE 0 END), 0) AS alipay, COALESCE(SUM(CASE WHEN pay_method = '微信' THEN paid_amount ELSE 0 END) - SUM(CASE WHEN refund_method = '微信' THEN refund_amount ELSE 0 END), 0) AS wechat, COALESCE(SUM(CASE WHEN pay_method = '银行卡' THEN paid_amount ELSE 0 END) - SUM(CASE WHEN refund_method = '银行卡' THEN refund_amount ELSE 0 END), 0) AS bank FROM clinic_charge_order WHERE deleted = 0 AND DATE(COALESCE(paid_at, created_at)) >= #{startDate} AND DATE(COALESCE(paid_at, created_at)) <= #{endDate} AND department_name = #{department}
AND (order_no LIKE CONCAT('%', #{keyword}, '%') OR patient_name LIKE CONCAT('%', #{keyword}, '%') OR department_name LIKE CONCAT('%', #{keyword}, '%'))
GROUP BY department_name ORDER BY received DESC

SELECT COALESCE(c.doctor_name, '未分配') AS doctor, COALESCE(SUM(c.receivable_amount), 0) AS receivable, COALESCE(SUM(c.discount_amount), 0) AS discount, COALESCE(SUM(c.paid_amount - COALESCE(c.refund_amount, 0)), 0) AS received, COUNT(*) AS visits, SUM(CASE WHEN r.visit_type = '初诊' THEN 1 ELSE 0 END) AS firstVisits, SUM(CASE WHEN r.visit_type = '复诊' THEN 1 ELSE 0 END) AS returnVisits, COALESCE(SUM(CASE WHEN c.charge_type LIKE '%西药%' OR c.charge_type LIKE '%成药%' OR c.charge_type LIKE '%药品零售%' OR c.remark LIKE '%药品%' THEN c.paid_amount - COALESCE(c.refund_amount, 0) ELSE 0 END), 0) AS westernDrug, COALESCE(SUM(CASE WHEN c.charge_type LIKE '%中药%' OR c.remark LIKE '%中药%' THEN c.paid_amount - COALESCE(c.refund_amount, 0) ELSE 0 END), 0) AS chineseDrug, COALESCE(SUM(CASE WHEN c.charge_type LIKE '%检查%' OR c.charge_type LIKE '%检验%' OR c.remark REGEXP '检查|检验|心电|彩超|血常规' THEN c.paid_amount - COALESCE(c.refund_amount, 0) ELSE 0 END), 0) AS checkProject, COALESCE(SUM(CASE WHEN c.charge_type LIKE '%挂号%' THEN c.paid_amount - COALESCE(c.refund_amount, 0) ELSE COALESCE(r.registration_fee, 0) END), 0) AS registration, COALESCE(SUM(CASE WHEN c.charge_type LIKE '%诊疗%' THEN c.paid_amount - COALESCE(c.refund_amount, 0) ELSE COALESCE(r.diagnosis_fee, 0) END), 0) AS diagnosis FROM clinic_charge_order c LEFT JOIN clinic_registration r ON r.id = c.registration_id AND r.deleted = 0 WHERE c.deleted = 0 AND DATE(COALESCE(c.paid_at, c.created_at)) >= #{startDate} AND DATE(COALESCE(c.paid_at, c.created_at)) <= #{endDate} AND c.doctor_name = #{doctor}
AND (c.order_no LIKE CONCAT('%', #{keyword}, '%') OR c.patient_name LIKE CONCAT('%', #{keyword}, '%') OR c.doctor_name LIKE CONCAT('%', #{keyword}, '%'))
GROUP BY c.doctor_name ORDER BY received DESC

choose.otherwise:
SELECT id, order_no AS orderNo, patient_name AS patientName, charge_type AS chargeType,
       department_name AS departmentName, doctor_name AS doctorName,
       receivable_amount AS receivableAmount, discount_amount AS discountAmount,
       paid_amount AS paidAmount, refund_amount AS refundAmount, pay_method AS payMethod,
       refund_method AS refundMethod, status, cashier, paid_at AS paidAt, refunded_at AS refundedAt
FROM clinic_charge_order WHERE deleted = 0
AND DATE(COALESCE(paid_at, created_at)) >= #{startDate}
AND DATE(COALESCE(paid_at, created_at)) <= #{endDate}

  AND (order_no LIKE CONCAT('%', #{keyword}, '%') OR patient_name LIKE CONCAT('%', #{keyword}, '%'))

AND department_name = #{department}
AND cashier = #{cashier}
AND doctor_name = #{doctor}


    AND (charge_type LIKE '%挂号%' OR UPPER(charge_type) LIKE '%REGISTRATION%' OR UPPER(charge_type) LIKE '%REGISTER%')
    AND (charge_type LIKE '%药品零售%' OR UPPER(charge_type) LIKE '%DRUG_RETAIL%' OR UPPER(charge_type) LIKE '%RETAIL%')
    AND (charge_type LIKE '%处方%' OR charge_type LIKE '%门诊%' OR UPPER(charge_type) LIKE '%PRESCRIPTION%' OR UPPER(charge_type) LIKE '%OUTPATIENT%')
    AND charge_type = #{orderType}


ORDER BY id DESC

choose.when:
SELECT COALESCE(r.visit_type,'未知') AS name, COUNT(*) AS value
FROM clinic_registration r
WHERE r.deleted = 0
AND DATE(r.visit_time) >= #{startDate}
AND DATE(r.visit_time) <= #{endDate}
GROUP BY COALESCE(r.visit_type,'未知')

choose.otherwise:
SELECT r.id, r.visit_time AS visitTime, r.patient_id AS patientId, r.patient_name AS patientName, r.gender, r.age, r.phone, r.visit_type AS visitType, c.diagnosis, r.department_name AS departmentName, r.doctor_name AS doctorName, COALESCE(co.status, 'PENDING') AS chargeStatus, r.status AS visitStatus FROM clinic_registration r LEFT JOIN clinic_consultation c ON c.registration_id = r.id AND c.deleted = 0 LEFT JOIN clinic_charge_order co ON co.id = ( SELECT co2.id FROM clinic_charge_order co2 WHERE co2.deleted = 0 AND co2.registration_id = r.id ORDER BY co2.id DESC LIMIT 1 ) WHERE r.deleted = 0 AND DATE(r.visit_time) >= #{startDate} AND DATE(r.visit_time) <= #{endDate} AND r.doctor_name = #{doctor}
AND (r.patient_name LIKE CONCAT('%', #{keyword}, '%') OR r.phone LIKE CONCAT('%', #{keyword}, '%'))
AND (co.id IS NULL OR co.status IN ('PENDING', 'PARTIAL')) AND co.status = 'PAID' AND co.status = 'REFUNDED' AND co.status = #{chargeStatus}
ORDER BY r.visit_time DESC

choose.when:
SELECT i.drug_id AS drugId, i.drug_code AS drugCode, i.drug_name AS drugName, i.batch_no AS batchNo, i.category, i.specification, i.manufacturer, i.unit, i.quantity AS endQty, CASE WHEN i.quantity = 0 THEN 0 ELSE ROUND(i.purchase_amount / i.quantity, 2) END AS endPrice, i.purchase_amount AS endAmount, 0 AS initialQty, 0 AS initialAmount, 0 AS initialPrice, COALESCE(lg.increaseQty, 0) AS increaseQty, CASE WHEN COALESCE(lg.increaseQty, 0) = 0 THEN 0 ELSE ROUND(COALESCE(lg.increaseAmount, 0) / lg.increaseQty, 2) END AS increasePrice, COALESCE(lg.increaseAmount, 0) AS increaseAmount, COALESCE(lg.decreaseQty, 0) AS decreaseQty, CASE WHEN COALESCE(lg.decreaseQty, 0) = 0 THEN 0 ELSE ROUND(COALESCE(lg.decreaseAmount, 0) / lg.decreaseQty, 2) END AS decreasePrice, COALESCE(lg.decreaseAmount, 0) AS decreaseAmount, i.purchase_amount AS purchaseAmount, i.retail_amount AS retailAmount, i.expire_date AS expireDate, COALESCE(lg.lastOperateAt, i.updated_at) AS updatedAt FROM clinic_inventory i LEFT JOIN ( SELECT inventory_id, SUM(CASE WHEN change_quantity > 0 THEN change_quantity ELSE 0 END) AS increaseQty, SUM(CASE WHEN change_quantity > 0 THEN change_quantity * unit_purchase_price ELSE 0 END) AS increaseAmount, SUM(CASE WHEN change_quantity < 0 THEN ABS(change_quantity) ELSE 0 END) AS decreaseQty, SUM(CASE WHEN change_quantity < 0 THEN ABS(change_quantity) * unit_purchase_price ELSE 0 END) AS decreaseAmount, MAX(created_at) AS lastOperateAt FROM ( SELECT l.*, CASE WHEN i2.quantity = 0 THEN 0 ELSE i2.purchase_amount / i2.quantity END AS unit_purchase_price FROM clinic_inventory_log l LEFT JOIN clinic_inventory i2 ON i2.id = l.inventory_id AND i2.deleted = 0 WHERE l.deleted = 0 ) x GROUP BY inventory_id ) lg ON lg.inventory_id = i.id WHERE i.deleted = 0 AND DATE(COALESCE(lg.lastOperateAt, i.updated_at)) >= #{startDate} AND DATE(COALESCE(lg.lastOperateAt, i.updated_at)) <= #{endDate}
AND (i.drug_name LIKE CONCAT('%', #{keyword}, '%') OR i.drug_code LIKE CONCAT('%', #{keyword}, '%') OR i.batch_no LIKE CONCAT('%', #{keyword}, '%') OR i.manufacturer LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY COALESCE(lg.lastOperateAt, i.updated_at) DESC, i.id DESC

SELECT p.id, CONCAT('ADJ', LPAD(p.id, 8, '0')) AS orderNo, p.drug_id AS drugId, p.drug_code AS drugCode, p.drug_name AS drugName, i.specification, i.manufacturer, i.batch_no AS batchNo, i.quantity AS stock, i.unit, p.old_purchase_price AS oldPurchasePrice, p.new_purchase_price AS newPurchasePrice, p.old_sell_price AS oldSellPrice, p.new_sell_price AS newSellPrice, p.operator, p.reason, p.created_at AS createdAt FROM clinic_price_adjustment p LEFT JOIN clinic_inventory i ON i.drug_id = p.drug_id AND i.deleted = 0 WHERE p.deleted = 0 AND DATE(p.created_at) >= #{startDate} AND DATE(p.created_at) <= #{endDate}
AND (p.drug_name LIKE CONCAT('%', #{keyword}, '%') OR p.drug_code LIKE CONCAT('%', #{keyword}, '%') OR i.batch_no LIKE CONCAT('%', #{keyword}, '%') OR CONCAT('ADJ', LPAD(p.id, 8, '0')) LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY p.id DESC

choose.otherwise:
SELECT so.id, so.order_no AS orderNo, so.stock_direction AS stockDirection, so.stock_type AS stockType, so.supplier_name AS supplierName, so.maker, so.operator, so.audit_status AS auditStatus, so.audit_at AS auditAt, so.created_at AS createdAt, i.drug_id AS drugId, i.drug_code AS drugCode, i.drug_name AS drugName, i.specification, i.manufacturer, i.batch_no AS batchNo, i.unit, ABS(COALESCE(l.change_quantity, 0)) AS quantity, CASE WHEN i.quantity = 0 THEN 0 ELSE ROUND(i.purchase_amount / i.quantity, 2) END AS purchasePrice, COALESCE(ABS(l.change_quantity) * CASE WHEN i.quantity = 0 THEN 0 ELSE i.purchase_amount / i.quantity END, so.purchase_amount) AS purchaseAmount, so.retail_amount AS retailAmount FROM clinic_stock_order so LEFT JOIN clinic_inventory_log l ON l.business_no = so.order_no AND l.deleted = 0 LEFT JOIN clinic_inventory i ON i.id = l.inventory_id AND i.deleted = 0 WHERE so.deleted = 0 AND so.stock_direction = 'IN' AND so.stock_direction = 'OUT' AND DATE(so.created_at) >= #{startDate} AND DATE(so.created_at) <= #{endDate} AND so.stock_type = #{stockInType} AND so.stock_type = #{stockOutType}
AND (so.order_no LIKE CONCAT('%', #{keyword}, '%') OR so.supplier_name LIKE CONCAT('%', #{keyword}, '%') OR so.remark LIKE CONCAT('%', #{keyword}, '%') OR i.drug_name LIKE CONCAT('%', #{keyword}, '%') OR i.drug_code LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY so.id DESC, l.id DESC

mapper.select:
SELECT id, CONCAT('CHK', DATE_FORMAT(created_at, '%Y%m%d'), LPAD(id, 4, '0')) AS orderNo, project_code AS projectCode, name, category, price, unit, status, created_at AS createdAt FROM clinic_check_project WHERE deleted = 0 AND DATE(created_at) >= #{startDate} AND DATE(created_at) <= #{endDate}
AND (project_code LIKE CONCAT('%', #{keyword}, '%') OR name LIKE CONCAT('%', #{keyword}, '%') OR CONCAT('CHK', DATE_FORMAT(created_at, '%Y%m%d'), LPAD(id, 4, '0')) LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY id DESC
